import{_ as t,a as e}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as s,o as i,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"ユーザー頻度制限","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Safety/user-rate-limits.md","filePath":"ja-JP/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),d={name:"ja-JP/Safety/user-rate-limits.md"};function n(o,a,p,h,c,u){return i(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="ユーザー頻度制限" tabindex="-1">ユーザー頻度制限 <a class="header-anchor" href="#ユーザー頻度制限" aria-label="Permalink to &quot;ユーザー頻度制限&quot;">​</a></h1><p>ユーザー頻度制限は、短時間に大量アップロードやアクセスが発生したときに、利用を抑制するための機能です。</p><p>公開アップロードを許可しているサイトでは、スパム投稿や過剰利用を防ぐために設定しておくと安心です。</p><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; セキュリティ設定 -&gt; ユーザー頻度制限</span></span></code></pre></div><p><img src="'+t+`" alt="頻度制限" loading="lazy"></p><h2 id="主な設定" tabindex="-1">主な設定 <a class="header-anchor" href="#主な設定" aria-label="Permalink to &quot;主な設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>有効</td><td>頻度制限をオン / オフします</td></tr><tr><td>時間範囲</td><td>判定する時間窓を指定します</td></tr><tr><td>上限回数</td><td>時間範囲内で許可する操作回数を指定します</td></tr><tr><td>対象操作</td><td>アップロードなど、制限したい操作を選びます</td></tr><tr><td>ブロック時間</td><td>上限を超えたあと、どれくらい制限するかを指定します</td></tr></tbody></table><h2 id="使い方の例" tabindex="-1">使い方の例 <a class="header-anchor" href="#使い方の例" aria-label="Permalink to &quot;使い方の例&quot;">​</a></h2><p>公開アップロードを許可している場合は、まずゆるめの制限から始め、実際の利用状況を見ながら調整します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10 分間で 30 回まで</span></span>
<span class="line"><span>超過時は 30 分ブロック</span></span></code></pre></div><p>このように設定すると、通常利用は邪魔しにくく、明らかに不自然な連続アップロードを止めやすくなります。</p><h2 id="エラー表示" tabindex="-1">エラー表示 <a class="header-anchor" href="#エラー表示" aria-label="Permalink to &quot;エラー表示&quot;">​</a></h2><p>制限にかかったユーザーには、アップロードや操作が拒否されたことを示すメッセージが表示されます。</p><p><img src="`+e+'" alt="頻繁なエラー表示" loading="lazy"></p><h2 id="調整のポイント" tabindex="-1">調整のポイント <a class="header-anchor" href="#調整のポイント" aria-label="Permalink to &quot;調整のポイント&quot;">​</a></h2><ul><li>制限が強すぎると、通常ユーザーの連続アップロードまで止まります。</li><li>公開サイトでは、最初から完全に無制限にしない方が安全です。</li><li>IP 位置情報やユーザー管理と組み合わせると、不審な利用を追いやすくなります。</li><li>大きなイベントや一時的な利用増加がある場合は、上限を一時的に緩めても構いません。</li></ul>',17)])])}const g=s(d,[["render",n]]);export{_ as __pageData,g as default};
